<# .SYNOPSIS Offline regression for model portfolio and evidence-first fusion. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..\..')).Path;$validator=Join-Path $PSScriptRoot 'validate-fusion-plan.ps1';$temp=Join-Path $root '.qianlima\tmp\fusion-test.json';New-Item -ItemType Directory -Path (Split-Path $temp) -Force|Out-Null
function RunPlan($risk,$models,$human){$refs=@($models|ForEach-Object { 'claim-pack:'+$_ });$plan=[ordered]@{fusion_id='fusion-test-'+$risk;task_id='task-fusion-test';risk_level=$risk;selected_models=$models;selection_reason='uncertainty';independence_requirement='distinct_provider_or_version';allowed_input_refs=@('evidence:public-1');data_classification='public';candidate_budget=[ordered]@{max_calls=4;max_cost_usd=1};fusion_method='evidence_first_claim_pack';verifier='evidence_checker';claim_pack_refs=$refs;stop_conditions=@('evidence_sufficient','conflict_found');human_approval_requirement=$human;status='draft'};[IO.File]::WriteAllText($temp,($plan|ConvertTo-Json -Depth 8),[Text.UTF8Encoding]::new($false));$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $validator -PlanPath $temp -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;result=($out -join "`n")}}
$cases=[System.Collections.Generic.List[object]]::new();$l0=RunPlan 'L0' @('model-a') 'not_required';$l3=RunPlan 'L3' @('model-a','model-b') 'not_required';$l4=RunPlan 'L4' @('model-a','model-b') 'required';$bad=RunPlan 'L3' @('model-a') 'not_required';$cases.Add([pscustomobject]@{name='L0_fusion_denied';passed=($l0.code -ne 0)});$cases.Add([pscustomobject]@{name='L3_independent_candidates_allowed';passed=($l3.code -eq 0)});$cases.Add([pscustomobject]@{name='L4_returns_needs_human';passed=($l4.code -eq 0 -and ($l4.result -match 'needs_human'))});$cases.Add([pscustomobject]@{name='L3_single_candidate_denied';passed=($bad.code -ne 0)});$failed=@($cases | Where-Object { -not $_.passed });$result=[pscustomobject]@{passed=($failed.Count -eq 0);cases=@($cases);external_calls=$false;permissions_granted=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Model fusion regression failed: '+(($failed.name) -join ', '))}
